#include<iostream>#include<set>#include<vector>#include<algorithm>using namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n,k;        cin>>n>>k;        vector<int>a(n);        set<int>s;        for(int i=0;i<n;i++){            cin>>a[i];            s.insert(a[i]);        }         bool possible= false;        for(int i=0;i<n;i++){            if(s.count(a[i] - k)){                possible=true;                break;            }                    }        if(possible)cout<<"yes\n";        else cout<<"no\n";    } }